# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
from collections import defaultdict
import numpy as np
import os
import joblib
from PIL import Image
import cv2

app = Flask(__name__)

# Data storage
labels = defaultdict(list)
images = {}

@app.route('/upload_image', methods=['POST'])
def upload_image():
    file = request.files['image']
    image_id = request.form['image_id']
    image_path = os.path.join('images', image_id)
    file.save(image_path)
    images[image_id] = image_path
    return jsonify({'message': 'Image uploaded successfully.'}), 201

@app.route('/label_image', methods=['POST'])
def label_image():
    image_id = request.form['image_id']
    label = request.form['label']
    labels[image_id].append(label)
    
    return jsonify({'message': 'Label submitted successfully.'}), 201

@app.route('/aggregate_labels', methods=['GET'])
def aggregate_labels():
    aggregated_labels = {}
    for image_id, votes in labels.items():
        if votes:
            aggregated_labels[image_id] = max(set(votes), key=votes.count)
    return jsonify(aggregated_labels), 200

@app.route('/train_model', methods=['POST'])
def train_model():
    # Dummy training data for illustration
    X = []
    y = []
    
    for image_id, label in labels.items():
        img = cv2.imread(images[image_id])
        img_resized = cv2.resize(img, (100, 100)).flatten()
        X.append(img_resized)
        majority_label = max(set(label), key=label.count)
        y.append(majority_label)
    
    # Dummy training process (replace with the actual model)
    model = {'X': np.array(X), 'y': np.array(y)}  # Replace with actual model training
    joblib.dump(model, 'trained_model.pkl')
    return jsonify({'message': 'Model trained successfully.'}), 200

if __name__ == '__main__':
    if not os.path.exists('images'):
        os.makedirs('images')
    app.run(debug=True)